    ('LING-L 700', 'SEMINAR ON CURRENT ISSUES', '14330', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 240', 'Shobhana Chelliah', 13, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This seminar will deal with major books and articles which have defined important areas of debate in the current development of linguistic theory. The specific title will be announced well in advance of each semester.', ARRAY[]::TEXT[], NULL),
    ('LING-L 715', 'SEMINAR IN COMPUTATIONAL LINGUISTICS', '10343', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 221', 'Damir Cavar', 1, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The seminar will introduce students to current research in the field of Computational Linguistics.', ARRAY[]::TEXT[], NULL),
    ('LING-L 720', 'SEMINAR IN SOCIOLINGUISTICS', '29660', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 317', 'Monica Nesbitt', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 800', 'RESEARCH', '2086', 'Class Status', NULL, NULL, 'Sandra Kuebler', 29, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 800', 'RESEARCH', '6856', 'Class Status', NULL, NULL, 'Sandra Kuebler', 37, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-X 471', 'UNDERGRADUATE TEACHING INTERNSHIP IN LINGUISTICS', '11425', 'Class Status', NULL, NULL, 'Ann Bunger, Kelly Berkson', 6, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students assist a faculty member in preparation and/or implementation of an undergraduate Linguistics course. Duties may include developing course materials, assisting with classroom activities and instruction, peer tutoring, and more. Interns do not participate in grading.', ARRAY[]::TEXT[], NULL),
    ('LING-X 473', 'INTERNSHIP IN LINGUISTICS', '12408', 'Class Status', NULL, NULL, 'Ann Bunger', 10, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students work on extracurricular projects in the context of an industrial setting, a non-profit institution, or a laboratory setting. Projects must be related to issues of language structure or use, including research and application.', ARRAY[]::TEXT[], NULL),
    ('LING-X 477', 'FIELD EXPERIENCE IN LINGUISTICS', '9075', 'Class Status', NULL, NULL, 'Ann Bunger', 20, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students work on extracurricular projects in the area of language documentation. Projects may be carried out in a language community, in an academic setting, or in the context of a non-profit institution.', ARRAY[]::TEXT[], NULL),
    ('LING-X 490', 'READINGS IN LINGUISTICS', '2080', 'Class Status', NULL, NULL, 'Shobhana Chelliah', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], 'Directed reading in various fields of linguistics.', ARRAY[]::TEXT[], NULL),
