    ('LING-X 490', 'READINGS IN LINGUISTICS', '15355', 'Class Status', NULL, NULL, 'Luke Gessler', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], 'Directed reading in various fields of linguistics.', ARRAY[]::TEXT[], NULL),
    ('LLLC-Y 101', 'TECHNOLOGY LEADERSHIP AND INNOVATION I', '8115', 'Class Status', 'M Monday 11:10 AM–12:25 PM', 'TE F160', 'Nicole Mitchell', 17, NULL, 'Lecture', '1.5', 'TETER QUAD', ARRAY[]::TEXT[], 'This course will focus on developing student leaders by providing resources and tools to empower them in setting goals, teamwork, communication, and decision-making skills. Students will have an opportunity to interact and develop relationships with School of Informatics and Computing faculty, staff, alumni, upper class students, and conduct research.', ARRAY[]::TEXT[], NULL),
    ('LLLC-Y 101', 'TECHNOLOGY LEADERSHIP AND INNOVATION I', '9322', 'Class Status', 'Tu Tuesday 9:35 AM–10:50 AM', 'TE F160', 'Nicole Mitchell', 14, NULL, 'Lecture', '1.5', 'TETER QUAD', ARRAY[]::TEXT[], 'This course will focus on developing student leaders by providing resources and tools to empower them in setting goals, teamwork, communication, and decision-making skills. Students will have an opportunity to interact and develop relationships with School of Informatics and Computing faculty, staff, alumni, upper class students, and conduct research.', ARRAY[]::TEXT[], NULL),
    ('LLLC-Y 101', 'TECHNOLOGY LEADERSHIP AND INNOVATION I', '10104', 'Class Status', 'Tu Tuesday 12:45 PM–2:00 PM', 'TE F160', 'Nicole Mitchell', 21, NULL, 'Lecture', '1.5', 'TETER QUAD', ARRAY[]::TEXT[], 'This course will focus on developing student leaders by providing resources and tools to empower them in setting goals, teamwork, communication, and decision-making skills. Students will have an opportunity to interact and develop relationships with School of Informatics and Computing faculty, staff, alumni, upper class students, and conduct research.', ARRAY[]::TEXT[], NULL),
    ('LLLC-Y 101', 'TECHNOLOGY LEADERSHIP AND INNOVATION I', '12892', 'Class Status', 'M Monday 9:35 AM–10:50 AM', 'TE F160', 'Nicole Mitchell', 28, NULL, 'Lecture', '1.5', 'TETER QUAD', ARRAY[]::TEXT[], 'This course will focus on developing student leaders by providing resources and tools to empower them in setting goals, teamwork, communication, and decision-making skills. Students will have an opportunity to interact and develop relationships with School of Informatics and Computing faculty, staff, alumni, upper class students, and conduct research.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 100', 'SURVEY OF UNIONS AND COLLECTIVE BARGAINING', '5443', 'Closed', NULL, 'WB WEB', 'Danny Ernstes', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A survey of labor unions in the United States, focusing on their organization and their representational, economic and political activities. Includes coverage of historical development, labor law basics, and contemporary issues.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 101', 'AMERICAN LABOR HISTORY', '2090', 'Class Status', NULL, 'WB WEB', 'Joseph Varga', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A survey of the origin and development of unions and the labor movement from colonial times to the present. The struggle of working people to achieve a measure of dignity and security will be examined from social, economic and political perspectives.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('LSTU-L 104', 'INTRODUCTION TO THE STUDY OF LABOR HISTORY', '4216', 'Class Status', NULL, 'WB WEB', 'Joseph Varga', 16, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'What can be learned from labor history? This class explores both central issues as well as historical methodologies looking at primary and secondary sources, considering bias and interpretation. Focusing on a few central questions and events, this class serves as an orientation for the study of labor history.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 110', 'INTRODUCTION TO LABOR STUDIES: LABOR AND SOCIETY', '3438', 'Closed', NULL, 'WB WEB', 'Patricia Linner', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will introduce students to the interdisciplinary and advocacy approach of labor studies. Exploring labor''s role in society, the class will look at how unions have changed the lives of working people and contributed to better social policies. Discussions will highlight the relationship of our work lives to our nonwork lives and will look at U.S. labor relations in comparative framework.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('LSTU-L 110', 'INTRODUCTION TO LABOR STUDIES: LABOR AND SOCIETY', '3590', 'Closed', NULL, 'WB WEB', 'Patricia Linner', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will introduce students to the interdisciplinary and advocacy approach of labor studies. Exploring labor''s role in society, the class will look at how unions have changed the lives of working people and contributed to better social policies. Discussions will highlight the relationship of our work lives to our nonwork lives and will look at U.S. labor relations in comparative framework.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('LSTU-L 200', 'SURVEY OF EMPLOYMENT LAW', '11964', 'Class Status', NULL, 'WB WEB', 'Tyler Helmond', 17, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Statutes and common law actions protecting income, working conditions, and rights of workers. Topics include workers'' compensation, unemployment compensation, fair labor standards, social security, retirement income protection, privacy and other rights.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 203', 'LABOR AND THE POLITICAL SYSTEM', '9674', 'Closed', NULL, 'WB WEB', 'Donny Jones', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Federal, state and local governmental effects on workers, unions, and labor-management relations; political goals; influences on union choices of strategies and modes of political participation, past and present; relationships with community and other groups.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 205', 'CONTEMPORARY LABOR PROBLEMS', '11961', 'Class Status', NULL, 'WB WEB', 'Patricia Linner', 15, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An examination of some of the major problems confronting society, workers, and the labor movement. Topics may include: automation, unemployment, international trade and conglomerates; environmental problems, minority and women''s rights; community relations; changing government policies.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 230', 'LABOR AND THE ECONOMY', '9675', 'Closed', NULL, 'WB WEB', 'Gregor Koso', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Analysis of the political economy of labor and the role of organized labor within it. Emphasis on the effect on workers, unions, and collective bargaining of unemployment, investment policy, and changes in technology and corporate structure. Patterns of union political and bargaining response.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('LSTU-L 260', 'LEADERSHIP AND REPRESENTATION', '13944', 'Closed', NULL, 'WB WEB', 'Jerell Blakeley', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Organizational leadership issues for the union, community, and other advocate organizations. Analyzes leadership styles, membership recruitment and leadership development. Examines the role of leaders in internal governance and external affairs including committee building, delegation, negotiations, and condition building.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 271', 'FRAMED: LABOR AND THE MEDIA', '11747', 'Class Status', NULL, 'WB WEB', 'Cynthia Gwynne Yaudes', 13, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course examines media and public understanding of the U.S. labor movement and analyzes reaction to some specific, highly publicized strikes. News media, generally aligned with antilabor interests of corporate America, often portray "ordinary" workers as passive and controlled/directed by unions/labor leaders. This course questions why that might be.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 275', 'PROTECTING WORKER''S RIGHTS IN GLOBAL SUPPLY CHAINS', '11739', 'Closed', NULL, 'WB WEB', 'Cynthia Gwynne Yaudes', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores the impact of global supply chains (GSCs) on workers and their abilities to maintain adequate living standards, the regulatory frameworks under which trade, investment and taxation occur, and the strategies and tactics workers can use to create an alternative governing structure which promotes sustainable work and development within the GSC.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 289', 'WORK LIKE A GIRL: WOMEN''S EVOLVING WORKPLACE ROLE', '11740', 'Closed', NULL, 'WB WEB', 'Marquita Walker', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course interrogates, through the lens of political economy theory of discrimination, the current challenges women experience in various US and global workplaces. Included are theoretical discussions concerning the historical position of women in the labor force, the changing landscape of female workforce participation, and the intersection of work dynamics within the context of race, class, and gender. Issues of specific interest are wage disparities, job insecurity, and sexual harassment. An examination of strategies, programs, and initiatives to correct gender disparities and create inclusive workplaces follows.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 290', 'TOPICS IN LABOR STUDIES', '10027', 'Closed', NULL, 'WB WEB', 'William Mello', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is a number under which a variety of topics can be addressed in classroom-based programs on the campuses. Courses may focus on contemporary or special areas of labor studies, such as union education: others are directed toward specific categories of employees and labor organizations.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 290', 'TOPICS IN LABOR STUDIES', '11966', 'Closed', NULL, 'WB WEB', 'William Mello', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is a number under which a variety of topics can be addressed in classroom-based programs on the campuses. Courses may focus on contemporary or special areas of labor studies, such as union education: others are directed toward specific categories of employees and labor organizations.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 291', 'THE BULLY IN THE WORKPLACE', '11743', 'Class Status', NULL, 'WB WEB', 'Patricia Linner', 20, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This one (1) credit will examine the dynamics of workplace bullying. We will analyze the factors that contribute to bullying in the workplace. We will examine the types of personalities that allows bullies to perpetrate the harm and how bullies threaten, intimidate, humiliate, and sabotage both targets and workplace productivity.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 292', 'PREVENTING SEXUAL HARASSMENT IN THE WORKPLACE', '11745', 'Class Status', NULL, 'WB WEB', 'Patricia Linner', 20, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course examines all aspects of workplace and academic sexual harassment, including but not limited to definitions, history, federal and state law, EEOC guidelines and procedures, employer and school liability, personnel, school and contract language and policies, and personal perspectives. Reasons for/solutions to workplace and academic sexual harassment are discussed.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 294', 'STAFFING AS A SAFETY ISSUE', '11965', 'Class Status', NULL, 'WB WEB', 'Joseph Zanoni', 28, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Health Care Staffing and Total Worker Health explores the theory and practice of workforce staffing in health care considering the impact of health care management decisions related to staffing on quality of care for patients and occupational health for workers. Theoretical perspectives, research, union contracts and definitional constructs are examined/discussed.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 296', 'PREVENTING WORKFORCE VIOLENCE IN THE WORKPLACE', '11744', 'Class Status', 'Non Standard Session', 'WB WEB', 'Patricia Linner', 20, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will examine the causes, preventions, and individual risks for workers from the real/perceived threat of violence in the workplace. We will identify behavioral, environmental, and administrative factors that contribute or prevent the incidents of violence in the workplace.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 297', 'STRIKE! LABOR REVOLT IN AMERICA', '11746', 'Class Status', 'Non Standard Session', 'WB WEB', 'Marquita Walker', 32, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores strike as a mechanism of worker power and worker threat in American culture. Through readings and discussion, the unequal balance of power between labor/management is the backdrop for worker action necessitated by the inadequacy of protective worker legislative/deregulation/continued corporate assaults on workers and their well-being.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 298', 'AMERICAN DREAM IN THE AGE OF DECLINE', '11742', 'Class Status', NULL, 'WB WEB', 'Marquita Walker', 30, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'American Dream in the Age of Decline is the interdisciplinary exploration of frameworks within which the notion of the American Dream has been constructed and changed over time in relation to the working class.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 314', 'ETHICAL DILEMMAS IN THE WORKPLACE', '4817', 'Class Status', NULL, 'WB WEB', 'Darren Cushman-Wood', 18, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course explores the fundamental basis for ethical decision making in a workplace, both unionized and nonunionized. We will discuss specific considerations for making moral judgments within the work environment and explore the basis upon which those decisions are made.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 315', 'THE ORGANIZATION OF WORK', '5408', 'Class Status', NULL, 'WB WEB', 'Gregor Koso', 23, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines how work is organized and jobs are evaluated, measured and controlled. Explores social and technical elements of work through theories of scientific management, the human relations school of management, and contemporary labor process literature.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 320', 'GRIEVANCE ARBITRATION', '11192', 'Class Status', NULL, 'WB WEB', 'Tyler Helmond', 31, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The legal and practical context of grievance arbitration, its limitations and advantages in resolving workplace problems. Varieties of arbitration clauses and the status of awards. Participants analyze, research, prepare, and present cases in mock arbitration hearings.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 331', 'GLOBAL PROBLEMS: LOCAL SOLUTIONS', '11193', 'Class Status', NULL, 'WB WEB', 'Joseph Varga', 30, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course examines local manifestations of global problems confronting society, workers, and labor by analyzing issues, creating solutions/activities to address these issues. Governmental, non-governmental, and charitable organizations that aid with local problems are examined and students design solutions for global situations characterized by flexibility, insecurity, and geographic mobility.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 370', 'LABOR AND RELIGION', '11962', 'Class Status', NULL, 'WB WEB', 'Darren Cushman-Wood', 22, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course has primarily a historical focus. It looks at the relationship between religion and the labor movement as it developed in the United States over the course of the 19th and 20th centuries. It attempts to uncover the tradition in which workers of faith have connected their religious values to their more secular concerns for social justice.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 380', 'THEORIES OF THE LABOR MOVEMENT', '7646', 'Class Status', NULL, 'WB WEB', 'Beverly Takahashi', 24, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Perspectives on the origin, development, and goals of organized labor. Theories include those which view the labor movement as: a business union institution; an agent for social reform; a revolutionary force; a psychological reaction to industrialization; a moral force; and an unnecessary intrusion.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 381', 'LATINOS, LABOR, AND MIGRATION IN THE US: CHALLENGING INVISIBILITY & DISTORTED IMAGES', '11963', 'Closed', NULL, 'WB WEB', 'William Mello', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course introduces students to the complex realities of Latinos in the United States focusing on the topics of work and migration. This includes the U.S. recruitment of Latino immigrants and Latino''s search for work whose homelands/economies are controlled/distorted/devastated to serves the interests of U.S. corporations/military actions.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 384', 'DIVERSITY AND INEQUALITY IN AMERICA', '11738', 'Class Status', NULL, 'WB WEB', 'William Mello', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course examines issues of diversity and income inequality in contemporary society by exploring the underlying political debate on how to address different forms of inequality and the way this debate impacts employment and workers in the United States.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 385', 'CLASS, RACE, GENDER AND WORK', '2091', 'Closed', NULL, 'WB WEB', 'Armand Chevaliér', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Historical overview of the impact and interplay of class, race, and gender on shaping U.S. labor markets, organizations, and policies. Examines union responses and strategies for addressing class, race, and gender issues.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 385', 'CLASS, RACE, GENDER AND WORK', '4366', 'Closed', NULL, 'WB WEB', 'Armand Chevaliér', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Historical overview of the impact and interplay of class, race, and gender on shaping U.S. labor markets, organizations, and policies. Examines union responses and strategies for addressing class, race, and gender issues.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 390', 'TOPICS IN LABOR STUDIES', '4217', 'Class Status', NULL, 'WB WEB', 'Joseph Zanoni', 24, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced courses in areas described under L290.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 390', 'TOPICS IN LABOR STUDIES', '6355', 'Class Status', NULL, 'WB WEB', 'Cynthia Gwynne Yaudes', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced courses in areas described under L290.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 390', 'TOPICS IN LABOR STUDIES', '6356', 'Class Status', NULL, 'WB WEB', 'Marquita Walker', 35, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced courses in areas described under L290.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 390', 'TOPICS IN LABOR STUDIES', '10028', 'Class Status', NULL, 'WB WEB', 'Jerell Blakeley', 17, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced courses in areas described under L290.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 390', 'TOPICS IN LABOR STUDIES', '10049', 'Closed', NULL, 'WB WEB', 'Joseph Zanoni', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced courses in areas described under L290.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 399', 'PRIOR LEARNING ASSESSMENTS', '13317', 'Class Status', NULL, 'WB WEB', 'Marquita Walker', 10, NULL, 'Demonstration', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Credit for labor-related competencies demonstrated, assessed and approved according to established procedures.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 420', 'LABOR STUDIES INTERNSHIP', '2092', 'Class Status', NULL, NULL, 'Staff', 5, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], 'Application of knowledge gained in the classroom in fieldwork experience.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 480', 'SENIOR SEMINAR OR READINGS', '2093', 'Class Status', NULL, NULL, 'Staff', 5, NULL, 'Readings', '3', NULL, ARRAY[]::TEXT[], 'Designed as either a class room seminar or directed reading. This course addresses current issues, historical developments, and other labor related concerns. Topics may vary each semester.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 490', 'TOPICS IN LABOR STUDIES', '11974', 'Class Status', NULL, 'WB WEB', 'Jerell Blakeley', 31, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced courses, including seminars, geared to specialized labor populations, issues, and areas of discipline.', ARRAY[]::TEXT[], NULL),
    ('LSTU-L 495', 'DIRECTED LABOR STUDY', '2094', 'Class Status', NULL, NULL, 'Staff', 5, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'A contract course to suit the special and varied needs and interests of individual students. The contract with the faculty member might include reading, directed application of prior course work, tutorials, or internships. Competencies assessed through written papers, projects, reports, or interviews.', ARRAY[]::TEXT[], NULL),
