    ('LTAM-L 226', 'TOPICS IN LATIN AMERICAN STUDIES', '34909', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–5:00 PM', 'WB WEB', 'Staff', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introduction to different aspects of Latin American and Caribbean cultures and societies. Topics will vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LTAM-L 226', 'TOPICS IN LATIN AMERICAN STUDIES', '37573', 'Class Status', 'MW Monday, Wednesday 1:55 PM–4:25 PM', 'WB WEB', 'Quetzil Castaneda', 25, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introduction to different aspects of Latin American and Caribbean cultures and societies. Topics will vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LTAM-L 280', 'INDIGENOUS RIGHTS, POLITICS, AND HISTORIES IN LATIN AMERICA', '37574', 'Class Status', 'TuTh Tuesday, Thursday 1:55 PM–4:25 PM', 'WB WEB', 'Quetzil Castaneda', 25, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Explores indigenous rights, politics and culture in the contexts of globalization, colonialism and neo-liberalism, focusing on Latin American indigenous peoples in Guatemala, México, and the Andes. Uses comparative and historical perspectives to examine how indigenous peoples have sought to attain human rights for their individual and collective selves as cultures and communities.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LTAM-L 326', 'TOPICS IN LATIN AMERICAN STUDIES', '14924', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SB 017', 'Sonia Manriquez', 26, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An introduction to different aspects of Latin American and/or Caribbean cultures and societies. Focuses on one topic or approach, which will vary. All readings in English.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('LTAM-L 326', 'TOPICS IN LATIN AMERICAN STUDIES', '34728', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 005', 'Patricia Basile', 7, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An introduction to different aspects of Latin American and/or Caribbean cultures and societies. Focuses on one topic or approach, which will vary. All readings in English.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('LTAM-L 526', 'SPECIAL TOPICS IN LATIN AMERICAN AND CARIBBEAN STUDIES', '34729', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 005', 'Patricia Basile', 3, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Intensive study and analysis of selected Latin American and Caribbean studies problems of limited scope within an interdisciplinary format. Topics will vary and will ordinarily cut across fields, regions or periods.', ARRAY[]::TEXT[], NULL),
    ('LTAM-L 527', 'LATIN AMERICAN AND CARIBBEAN LANGUAGES', '34910', 'Class Status', 'TuTh Tuesday, Thursday 3:00 PM–5:00 PM', 'WB WEB', 'Staff', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Languages of Latin America and the Caribbean, other than Spanish and Portuguese. The following languages are regularly offered: Nahuatl and Haitian Creole.', ARRAY[]::TEXT[], NULL),
