    ('LTAM-Q 201', 'INTERMEDIATE QUECHUA I', '8630', 'Class Status', 'MW Monday, Wednesday 9:50 AM–11:50 AM', 'WB WEB', 'Staff', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Focuses on more advanced grammatical constructions, vocabulary building, conversational drills, reading, and writing Quechua texts.', ARRAY['IUB GenEd World Language class'], NULL),
