    ('MATH-E 265', 'INTRODUCTION TO PROBABILITY AND STATISTICS FOR DATA SCIENCE', '9732', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'GY 1043', 'Mario Di Salvo', 2, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Covers elementary concepts of probability and statistics for data science, including combinatorics, conditional probability, independence, random variables, discrete and continuous distributions, moments, statistical inference, point estimation, quantiles, confidence intervals, test of hypotheses, and related topics. Introduces the application of data analysis to the social and natural sciences.', ARRAY[]::TEXT[], NULL),
    ('MATH-E 265', 'INTRODUCTION TO PROBABILITY AND STATISTICS FOR DATA SCIENCE', '13212', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'BH 206', 'Alex Glickfield', 11, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Covers elementary concepts of probability and statistics for data science, including combinatorics, conditional probability, independence, random variables, discrete and continuous distributions, moments, statistical inference, point estimation, quantiles, confidence intervals, test of hypotheses, and related topics. Introduces the application of data analysis to the social and natural sciences.', ARRAY[]::TEXT[], NULL),
    ('MATH-E 449', 'ADVANCED UNDERGRADUATE ENGINEERING MATHEMATICAL METHODS', '8679', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 105', 'Jia Shi', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Provides essential mathematical concepts and methods for solving problems encountered in many engineering fields. Topics selected from multivariable and vector calculus, coordinate transformations, infinite series, scaling and dimensional analysis, partial differential equations, integral transforms, linear algebra, discrete mathematics, and numerical methods.', ARRAY[]::TEXT[], NULL),
    ('MATH-G 901', 'ADVANCED RESEARCH', '37500', 'Class Status', NULL, NULL, 'Russell Lyons', 4, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
