    ('MATH-M 301', 'LINEAR ALGEBRA AND APPLICATIONS', '2155', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 002', 'Ji-Ping Sha', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Solving systems of linear equations, matrix algebra, determinants, vector spaces, eigenvalues and eigenvectors. Selection of advanced topics. Applications throughout. Computer used for theory and applications.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 301', 'LINEAR ALGEBRA AND APPLICATIONS', '12313', 'Class Status', 'MWF Monday, Wednesday, Friday 3:10 PM–4:00 PM', 'JH A106', 'Hector Pena Pollastri', 2, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Solving systems of linear equations, matrix algebra, determinants, vector spaces, eigenvalues and eigenvectors. Selection of advanced topics. Applications throughout. Computer used for theory and applications.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 301', 'LINEAR ALGEBRA AND APPLICATIONS', '29382', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 002', 'Ji-Ping Sha', 6, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Solving systems of linear equations, matrix algebra, determinants, vector spaces, eigenvalues and eigenvectors. Selection of advanced topics. Applications throughout. Computer used for theory and applications.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 303', 'LINEAR ALGEBRA FOR UNDERGRADUATES', '5424', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WH 121', 'Elijah Bodish', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction to the theory of real vector spaces. Coordinate systems, linear dependence, bases. Linear transformations and matrix calculus. Determinants and rank. Eigenvalues and eigenvectors.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 303', 'LINEAR ALGEBRA FOR UNDERGRADUATES', '12256', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WY 101', 'Yasin Uskuplu', 2, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introduction to the theory of real vector spaces. Coordinate systems, linear dependence, bases. Linear transformations and matrix calculus. Determinants and rank. Eigenvalues and eigenvectors.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 311', 'CALCULUS 3', '2156', 'Closed', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'BH 243', 'Peter Sternberg', 0, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Elementary geometry of 2, 3, and n-space, functions of several variables, partial differentiation, minimum and maximum problems, multiple integration.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 311', 'CALCULUS 3', '4215', 'Closed', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 1:55 PM–2:45 PM', 'SE 240', 'Michael Jolly', 0, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Elementary geometry of 2, 3, and n-space, functions of several variables, partial differentiation, minimum and maximum problems, multiple integration.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 311', 'CALCULUS 3', '5425', 'Closed', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 11:35 AM–12:25 PM', 'BH 343', 'Peter Sternberg', 0, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Elementary geometry of 2, 3, and n-space, functions of several variables, partial differentiation, minimum and maximum problems, multiple integration.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 312', 'CALCULUS 4', '2157', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 227', 'Ningchuan Zhang', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Differential calculus of vector valued functions, transformation of coordinated, change of variables in multiple integrals. Vector integral calculus: line integrals, Green''s theorem, surface integrals, Stokes'' theorem. Applications.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 330', 'EXPLORING MATHEMATICAL IDEAS', '12032', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SE 010', 'Yun Liu', 6, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'An experimental course to illustrate important ideas in major areas of mathematics, including number theory, group theory, topology, geometry, and probability. Additional topics may include newly emerging fields, such as chaos theory.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 343', 'INTRO TO DIFFERENTIAL EQUATIONS WITH APPLICATIONS I', '5153', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 242', 'Christopher Judge', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Ordinary differential equations and methods for their solution, including series methods and the Laplace transform. Applications of differential equations. Systems, stability, and numerical methods. Partial differential equations of mathematical physics, Fourier series.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 343', 'INTRO TO DIFFERENTIAL EQUATIONS WITH APPLICATIONS I', '12257', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'BH 307', 'Christopher Judge', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Ordinary differential equations and methods for their solution, including series methods and the Laplace transform. Applications of differential equations. Systems, stability, and numerical methods. Partial differential equations of mathematical physics, Fourier series.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 343', 'INTRO TO DIFFERENTIAL EQUATIONS WITH APPLICATIONS I', '35150', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'BH 142', 'Matthias Weber', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Ordinary differential equations and methods for their solution, including series methods and the Laplace transform. Applications of differential equations. Systems, stability, and numerical methods. Partial differential equations of mathematical physics, Fourier series.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 353', 'DISCRETE MATHEMATICS', '14117', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 009', 'Valery Lunts', 9, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Covers fundamental topics chosen from enumerative combinatorics and graph theory. Possible topics include permutations, combinations, pigeonhole principle, inclusion-exclusion, generating functions, recurrence relations, Pólya theory, spanning trees, Eulerian paths, Ramsey theory, graph coloring, flow problems, Hamiltonian paths and cycles, electrical networks, random graphs.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 365', 'INTRODUCTION TO PROBABILITY AND STATISTICS', '2158', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AD A151', 'Donggeun Ryou', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Elementary concepts of probability and statistics. Combinatorics, conditional probability, independence, random variables, discrete and continuous distributions, moments. Statistical inference, point estimation, confidence intervals, test of hypotheses. Applications to social and natural sciences.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 365', 'INTRODUCTION TO PROBABILITY AND STATISTICS', '5427', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'AD A151', 'Donggeun Ryou', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Elementary concepts of probability and statistics. Combinatorics, conditional probability, independence, random variables, discrete and continuous distributions, moments. Statistical inference, point estimation, confidence intervals, test of hypotheses. Applications to social and natural sciences.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 384', 'LOGIC', '32557', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'AD A151', 'Elif Uskuplu', 16, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Construction and study of formal mathematical languages. Definitions of, and relationships between, the notions of truth and provability of a formal sentence. Proof systems for logical systems such as propositional logic and syllogistic logic. Soundness, completeness, and decidability.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('MATH-M 403', 'INTRODUCTION TO MODERN ALGEBRA I', '2159', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 143', 'James Davis', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of groups, rings, field extensions, with applications to linear transformations.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 403', 'INTRODUCTION TO MODERN ALGEBRA I', '2160', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SW 103', 'Valery Lunts', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of groups, rings, field extensions, with applications to linear transformations.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 413', 'INTRODUCTION TO ANALYSIS 1', '3087', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SE 010', 'Ciprian Demeter', 9, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Modern theory of real number system, limits, functions, sequences and series, Riemann-Stieltjes integral, and special topics.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 413', 'INTRODUCTION TO ANALYSIS 1', '6065', 'Closed', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 143', 'Jonathan Hanselman', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Modern theory of real number system, limits, functions, sequences and series, Riemann-Stieltjes integral, and special topics.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 441', 'INTRODUCTION TO PARTIAL DIFFERENTIAL EQUATIONS WITH APPLICATIONS I', '2161', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WI C109', 'Kevin Zumbrun', 3, NULL, 'Lecture', '3', 'WILLKIE C', ARRAY[]::TEXT[], 'Derivation and methods of solution of classical partial differential equations of mathematical physics: heat, wave, and Laplace equations. Separation of variables, Fourier series, Sturm-Liouville theory, special functions. Green''s functions, Fourier transform, first order equations, characteristics and special topics.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 447', 'MATHEMATICAL MODELS AND APPLICATIONS I', '32149', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'BH 105', 'Jia Shi', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Formation and study of mathematical models used in the biological, social, and management sciences. Mathematical topics include games, graphs, Markov and Poisson processes, mathematical programming, queues, and equations of growth.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 463', 'INTRODUCTION TO PROBABILITY I', '2162', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 217', 'Elizabeth Housworth', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Counting techniques, the meaning of probability. Random experiments, conditional probability, independence. Random variables, expected values and standard deviations, moment generating functions, important discrete and continuous distributions. Poisson processes. Multivariate distributions, basic limit laws such as the central limit theorem.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 463', 'INTRODUCTION TO PROBABILITY I', '13976', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'SE 245', 'Norman Levenberg', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Counting techniques, the meaning of probability. Random experiments, conditional probability, independence. Random variables, expected values and standard deviations, moment generating functions, important discrete and continuous distributions. Poisson processes. Multivariate distributions, basic limit laws such as the central limit theorem.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 471', 'NUMERICAL ANALYSIS 1', '2163', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 243', 'Shouhong Wang', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interpolation and approximation of functions, numerical integration and differentiation, solution of nonlinear equations, acceleration and extrapolation, solution of systems of linear equations, eigenvalue problems, initial and boundary value problems for ordinary differential equations, and computer programs applying these numerical methods.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 491', 'PUTNAM EXAMINATION SEMINAR', '36856', 'Class Status', 'M Monday 5:20 PM–6:50 PM', 'RH 316', 'Hari Bercovici', 3, NULL, 'Lecture', '1', 'RAWLES HALL', ARRAY[]::TEXT[], 'The Putnam Examination is a national mathematics competition for college undergraduates at all levels of mathematics study. It is held in December each year. This problem seminar is designed to help student prepare for the examination.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 501', 'SURVEY OF ALGEBRA', '2165', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'RH 104', 'Julia Plavnik', 10, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MATH-M 507', 'INTRODUCTION TO LIE ALGEBRAS AND LIE GROUPS', '29380', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'RH 104', 'Matvei Libine', 1, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Nilpotent, solvable, and semisimple Lie algebras, exponential map, PBW theorem, Killing form, Cartan subalgebras, root systems, Weyl group, classification and representations of complex semisimple Lie algebras, Schur''s lemma, maximal weight modules; correspondence between real Lie algebras and Lie groups, compact Lie groups, complex and real semisimple Lie groups, symmetric spaces.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 511', 'REAL VARIABLES 1', '2166', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'RH 104', 'Shukun Wu', 7, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Sets and functions, cardinal and ordinal numbers, set functions, kinds of measures, integration, absolute continuity, convergence theorems, differentiation and integration. Normed linear spaces, function spaces,linear functionals, Banach spaces, Hilbert spaces, Fourier transforms, Schwartz class.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 513', 'COMPLEX VARIABLES 1', '2167', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 307', 'Hari Bercovici', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MATH-M 521', 'TOPOLOGY I', '6952', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'SB 231', 'Vladimir Touraev', 10, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Point set topology including connectedness, compactness, separation properties, products, quotients, metrization, function spaces. Elementary homotopy theory including fundamental group and covering spaces. Introduction to homology theory with applications such as the Brouwer Fixed Point theorem.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 531', 'METRIC GEOMETRY', '5963', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'RH 104', 'Matthias Weber', 9, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Introduction to the geometric study of metric spaces. Topics include: length spaces, model geometries, notions of curvature, Hadamard-Cartan theorem, convexity, metric-measure spaces.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 540', 'PARTIAL DIFFERENTIAL EQUATIONS I', '29375', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'BH 143', 'Hari Bercovici', 10, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Method of characteristics for first order PDE, Laplace, heat and wave equations. Maximum principles. Explicit solutions. Uniqueness of solutions.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 544', 'ORDINARY DIFFERENTIAL EQUATIONS I', '3086', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'RH 368', 'Shukun Wu', 6, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Existence of solutions; uniqueness of solutions; systems of differential equations; the nth order equation; linear differential equations; linear equations with analytic coefficients; asymptotic behavior; classification of singularities; formal solutions; the Frobenius method; self-adjoint eigenvalue problems; existence of eigenvalues; expansion and completeness theorems; perturbation of autonomous system; selected topics.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 563', 'THEORY OF PROBABILITY 1', '2168', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'RH 368', 'Russell Lyons', 5, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MATH-M 583', 'SET THEORY', '29381', 'Class Status', 'MWF Monday, Wednesday, Friday 1:55 PM–2:45 PM', 'BH 143', 'Larry Moss', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Zermelo-Fraenkel axioms for set theory, well-foundedness and well-orderings, induction and recursion, ordinals and cardinals, axiom of choice, cardinal exponentiation, generalized continuum hypothesis, infinite combinatorics and basic independence results.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 595', 'SEMINAR IN THE TEACHING OF COLLEGE MATHEMATICS I', '4378', 'Class Status', 'Tu Tuesday 3:55 PM–4:55 PM', 'BH 337', 'Chaojie Yuan', 1, NULL, 'Seminar', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Methods of teaching undergraduate college mathematics. Teaching Associates in the Mathematics Department are expected to enroll in this seminar during their first year of teaching at IU. Does not count toward meeting any of the 500 level requirements toward an M.A. or Ph.D.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 599', 'COLLOQUIUM', '2169', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 3:55 PM–5:25 PM', 'SE 105', 'James Davis', 49, NULL, 'Seminar', '1', 'SWAIN EAST', ARRAY[]::TEXT[], 'Attendance at Mathematics Department Colloquia required. May not be used in fulfillment of the thirty-six hours of 500, 600, or 700 level coursework required for Ph.D.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 623', 'GEOMETRIC TOPOLOGY I', '29377', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'RH 104', 'James Davis', 3, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Topics in geometric topology chosen from K-theory, simple homotopy theory, topology of manifolds, fiber bundles, knot theory, and related areas.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 633', 'ALGEBRAIC VARIETIES 1', '29379', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 312', 'Michael Larsen', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Geometric and cohomological properties of algebraic varieties and schemes.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 656', 'KINETIC THEORY AND STATISTICAL MECHANICS I', '29383', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'RH 368', 'Shouhong Wang', 4, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Introduction to the classical theory and modern developments. Historical development of kinetic-statistical theories; rigorous equilibrium statistics; kinetic gas dynamics according to Boltzmann equation; kinetic theories of transport processes in liquids.', ARRAY[]::TEXT[], NULL),
    ('MATH-M 701', 'SELECTED TOPICS IN ALGEBRA 1', '12025', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SW 103', 'Ajay Ramadoss', 4, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
