    ('MATH-M 731', 'SELECTED TOPICS IN DIFFERENTIAL GEOMETRY I', '12616', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'RH 104', 'Marlies Gerber', 10, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MATH-M 743', 'SELECTED TOPICS IN MATHEMATICAL PHYSICS I', '29376', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'RE C110', 'Mihai Ciucu', 10, NULL, 'Lecture', '3', 'READ HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
