    ('MELC-A 100', 'ELEMENTARY ARABIC I', '10273', 'Class Status', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'BH 217 WH 112', 'Issam Albdairat', 3, NULL, 'Lecture', '5', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Focuses on developing basic reading, writing, listening, and speaking skills in Modern Standard Arabic (MSA) and one dialect (Egyptian or Levantine). Also introduces some aspects of Arab culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('MELC-A 100', 'ELEMENTARY ARABIC I', '10274', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 344 WH 104', 'Issam Albdairat', 2, NULL, 'Lecture', '5', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Focuses on developing basic reading, writing, listening, and speaking skills in Modern Standard Arabic (MSA) and one dialect (Egyptian or Levantine). Also introduces some aspects of Arab culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('MELC-A 100', 'ELEMENTARY ARABIC I', '10275', 'Class Status', 'MW Monday, Wednesday 8:00 AM–8:50 AM', 'BH 241 BH 241', 'Ramazan Oduncu', 6, NULL, 'Lecture', '5', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Focuses on developing basic reading, writing, listening, and speaking skills in Modern Standard Arabic (MSA) and one dialect (Egyptian or Levantine). Also introduces some aspects of Arab culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('MELC-A 200', 'INTERMEDIATE ARABIC I', '10270', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SY 006 BH 241', 'Muhammad Abdo', 9, NULL, 'Lecture', '5', 'SYCAMORE HALL, BALLANTINE HALL', ARRAY[]::TEXT[], 'Intermediate course focuses on progressively more complex grammatical structures; continued expansion of vocabulary; and development of reading, writing, listening and speaking skills through intensive oral/aural practice using audio and video materials. Includes study of both Modern Standard Arabic (MSA) and one dialect (Egyptian or Levantine).', ARRAY['IUB GenEd World Language class'], NULL),
    ('MELC-A 200', 'INTERMEDIATE ARABIC I', '10271', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 314 ED 1084', 'Abdullah Omran', 3, NULL, 'Lecture', '5', 'SYCAMORE HALL, BALLANTINE HALL', ARRAY[]::TEXT[], 'Intermediate course focuses on progressively more complex grammatical structures; continued expansion of vocabulary; and development of reading, writing, listening and speaking skills through intensive oral/aural practice using audio and video materials. Includes study of both Modern Standard Arabic (MSA) and one dialect (Egyptian or Levantine).', ARRAY['IUB GenEd World Language class'], NULL),
    ('MELC-A 300', 'ADVANCED ARABIC I', '10261', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 243 BH 344', 'Batool Dasan', 4, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focuses on continued expansion of vocabulary, including appropriate collocations and idiomatic expressions, conjunctions, and accuracy in usage, improved pronunciation, and public speaking and presentation skills. Further develops reading, writing, listening, and speaking skills through oral/aural practice, including interactions with native speakers and extensive use of media produced in Arabic.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 320', 'LEVANTINE ARABIC I', '10347', 'Class Status', 'M Monday 3:00 PM–4:00 PM', 'WH 110', 'Issam Albdairat', 12, NULL, 'Activity', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Introductory course in Levantine Arabic that focuses on everyday conversations, including greetings, self-introductions, personal preferences, shopping, transportation, education, work, dining, hobbies, daily activities etc. Taught in the communicative, proficiency-based, approach to language instruction and includes extensive speaking and listening activities.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 330', 'MOROCCAN ARABIC I', '10181', 'Class Status', NULL, 'WB WEB', 'Abdessamad Mbarki', 15, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introduction to the Moroccan Arabic dialect focusing on basic interactions, including greetings, self-introductions, shopping, transportation, dining, accommodations, education, work, etc. Course will be taught in the communicative, proficiency-based approach to language instruction and will involve extensive in-class speaking practice, as well as one hour of weekly conversation practice.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 330', 'MOROCCAN ARABIC I', '12789', 'Class Status', NULL, 'WB WEB', 'Abdessamad Mbarki, Nader Morkus', 3, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introduction to the Moroccan Arabic dialect focusing on basic interactions, including greetings, self-introductions, shopping, transportation, dining, accommodations, education, work, etc. Course will be taught in the communicative, proficiency-based approach to language instruction and will involve extensive in-class speaking practice, as well as one hour of weekly conversation practice.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 400', 'ADVANCED ARABIC III', '3759', 'Class Status', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'BH 231 WH 006', 'Issam Albdairat', 14, NULL, 'Lecture', '4', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'An advanced Arabic language course, which builds on the Arabic structures and vocabulary taught in previous courses, with the goal of increasing proficiency in stylistic differences and usage.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 455', 'ADVANCED MEDIA ARABIC', '29746', 'Class Status', 'M Monday 10:50 AM–12:30 PM', 'AC C103 AC C103', 'Chaimaa Moukhtar', 13, NULL, 'Discussion', '4', 'CEDAR HALL', ARRAY[]::TEXT[], 'Introduces the language of the Arab media and develops communication skills in reading, presentational speaking, listening,interpersonal communication,and expository and persuasive writing. Covers current events in Arabic language mass media including diplomacy,demonstrations, elections,conflicts, business and finance, and social issues.Taught in Arabic', ARRAY[]::TEXT[], NULL),
    ('MELC-A 500', 'ELEMENTARY ARABIC I', '2707', 'Class Status', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'BH 217 WH 112', 'Issam Albdairat', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Modern standard Arabic as in contemporary literature, newspapers, and radio. Grammar, reading, dictation, composition, penmanship, conversation, translation.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 500', 'ELEMENTARY ARABIC I', '2708', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 344 WH 104', 'Issam Albdairat', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Modern standard Arabic as in contemporary literature, newspapers, and radio. Grammar, reading, dictation, composition, penmanship, conversation, translation.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 500', 'ELEMENTARY ARABIC I', '8345', 'Class Status', 'MW Monday, Wednesday 8:00 AM–8:50 AM', 'BH 241 BH 241', 'Ramazan Oduncu', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Modern standard Arabic as in contemporary literature, newspapers, and radio. Grammar, reading, dictation, composition, penmanship, conversation, translation.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 600', 'INTERMEDIATE ARABIC I', '2709', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SY 006 BH 241', 'Muhammad Abdo', 9, NULL, 'Drill', '3', 'SYCAMORE HALL, BALLANTINE HALL', ARRAY[]::TEXT[], 'This course serves as a progression from Elementary Arabic I & II, elevating students to the intermediate proficiency level. Students will attain the ability to engage in basic conversations, and navigate everyday communicative tasks within straightforward social contexts, discussing essential personal details and handling immediate needs.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 600', 'INTERMEDIATE ARABIC I', '2710', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 314 ED 1084', 'Abdullah Omran', 3, NULL, 'Drill', '3', 'SYCAMORE HALL, BALLANTINE HALL', ARRAY[]::TEXT[], 'This course serves as a progression from Elementary Arabic I & II, elevating students to the intermediate proficiency level. Students will attain the ability to engage in basic conversations, and navigate everyday communicative tasks within straightforward social contexts, discussing essential personal details and handling immediate needs.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 620', 'LEVANTINE ARABIC I', '11465', 'Class Status', 'M Monday 3:00 PM–4:00 PM', 'WH 110', 'Issam Albdairat', 12, NULL, 'Activity', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This is an introductory course of Levantine Arabic that focuses on everyday conversations, including greetings, self-introductions, personal preferences, shopping, transportation, education, work, dining, hobbies, daily activities etc. It will be taught in the communicative, proficiency-based, approach to language instruction, and will include extensive speaking and listening activities.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 630', 'MOROCCAN ARABIC I', '11466', 'Class Status', NULL, 'WB WEB', 'Abdessamad Mbarki', 15, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an introductory course of Moroccan Arabic, and it focuses on everyday conversations, including greetings, self-introductions, personal preferences, shopping, transportation, education, work, dining, hobbies, and daily activities. It will be taught in the communicative, proficiency-based, approach to language instruction, and will include extensive speaking and listening activities.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 630', 'MOROCCAN ARABIC I', '12790', 'Class Status', NULL, 'WB WEB', 'Abdessamad Mbarki, Nader Morkus', 3, NULL, 'Activity', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an introductory course of Moroccan Arabic, and it focuses on everyday conversations, including greetings, self-introductions, personal preferences, shopping, transportation, education, work, dining, hobbies, and daily activities. It will be taught in the communicative, proficiency-based, approach to language instruction, and will include extensive speaking and listening activities.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 655', 'ADVANCED MEDIA ARABIC', '29747', 'Class Status', 'M Monday 10:50 AM–12:30 PM', 'AC C103 AC C103', 'Chaimaa Moukhtar', 13, NULL, 'Activity', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Advanced Arabic Media provides students with the language of Arab media and develops their communication skills in reading, speaking, listening, interpersonal communication, and writing (expository and persuasive). Course covers current events in Arabic language mass media including diplomacy, demonstrations, elections, conflicts, business and finance, and social issues. Taught in Arabic.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 660', 'ADVANCED ARABIC I', '9379', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'BH 243 BH 344', 'Batool Dasan', 4, NULL, 'Discussion', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focuses on the continued development of speaking, listening, reading, and writing skills in modern standard Arabic. Materials drawn from classical prose will be introduced for study.', ARRAY[]::TEXT[], NULL),
    ('MELC-A 680', 'ADVANCED ARABIC III', '3855', 'Class Status', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'BH 231 WH 006', 'Issam Albdairat', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL, WOODBURN HALL', ARRAY[]::TEXT[], 'Builds on the Arabic structures and vocabulary taught in previous courses with the goal of increasing proficiency in stylistic differences and usage. Includes study of both Modern Standard Arabic (MSA) and one dialect (Egyptian or Levantine) and focuses on further developing reading, writing, listening, and speaking skills.', ARRAY[]::TEXT[], NULL),
    ('MELC-E 201', 'EGYPT OF THE PHARAOHS: HISTORY AND CIVILIZATION OF ANCIENT EGYPT', '29791', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0001', 'Stephen Vinson', 61, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Covers the history and civilization of ancient Egypt, including important historical and cultural events, from the Egyptian Predynastic period (c. 5000 - 3050 BCE) to the end of Egypt''s traditional culture (c. 450 CE).', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('MELC-E 300', 'DEMOTIC EGYPTIAN I: GRAMMAR AND SCRIPT', '36030', 'Closed', 'TuF Tuesday, Friday 9:35 AM–10:50 AM', 'BH 240', 'Stephen Vinson', 0, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to Demotic, the script and vernacular language of Ancient Egypt, in documented usage from around 650 BCE to circa 450 CE.', ARRAY[]::TEXT[], NULL),
    ('MELC-E 500', 'ELEMENTARY HIEROGLYPHIC EGYPTIAN I', '6656', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 11:35 AM–12:25 PM', 'BH 142', 'Stephen Vinson', 17, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course will introduce students to Middle Egyptian, the language of ancient Egypt as spoken and written during the Middle and Early New Kingdom, or c. 2000 - 1300 BCE. Students will learn the fundamentals of the hieroglyphic script, master basic grammatical concepts, and read and write simple sentences.', ARRAY[]::TEXT[], NULL),
    ('MELC-E 505', 'SEM IN ANCIENT EGYPTIAN HISTORY I: THE PREDYNASTIC PERIOD THROUGH THE END OF THE EIGHTEENTH DYNASTY', '29792', 'Class Status', 'W Wednesday 1:55 PM–4:25 PM', 'GY 1042', 'Stephen Vinson', 6, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'This course surveys the history, current historiography, and traditional views, of Egypt from the Late Predynastic Period through the Eighteenth Dynasty, c. 4000-1295 BCE. The course emphasizes political and economic history, with attention to cultural questions, particularly art and the religious aspects of the ideology of kingship.', ARRAY[]::TEXT[], NULL),
    ('MELC-E 600', 'INTERMEDIATE MIDDLE EGYPTIAN', '6658', 'Class Status', NULL, NULL, 'Stephen Vinson', 7, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Readings from Middle Egyptian prose and poetic texts of intermediate difficulty. Texts will include fictional narratives, royal inscriptions, personal letters, religious texts and tomb autobiographies.', ARRAY[]::TEXT[], NULL),
    ('MELC-E 660', 'DEMOTIC EGYPTIAN I: GRAMMAR AND SCRIPT', '14028', 'Class Status', 'TuF Tuesday, Friday 9:35 AM–10:50 AM', 'BH 240', 'Stephen Vinson', 8, NULL, 'Drill', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to Demotic, the script and vernacular language of Ancient Egypt, in documented usage from approximately 650 BCE to approximately 450 CE.', ARRAY[]::TEXT[], NULL),
    ('MELC-G 901', 'ADVANCED RESEARCH', '2711', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 16, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 215', 'MIDDLE EAST BEFORE ISLAM', '13788', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:15 PM', 'LH 135', 'Daniel Caner', 18, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'A historical and cultural survey of the ancient Middle East up to the rise of Muhammad, focusing on Persian, Greek and Roman eras and the rise of the Middle East as a center of cross-cultural competition and exchange.', ARRAY['IUB GenEd S&H credit
IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('MELC-M 233', 'THE GOLDEN AGE OF ISLAMIC CIVILIZATION', '13638', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 0013', 'Asma Afsaruddin', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Focuses on the Abbasid period of Islamic history, which began in 750 CE, and is considered the "golden age" of Islamic civilization due to remarkable accomplishments in culture, art, architecture, and scholarship during this time.', ARRAY['IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MELC-M 239', 'US FOREIGN POLICY AND THE MUSLIM WORLD', '9380', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'GA 0003', 'Mariam Taher', 45, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces salient policy debates that shape contemporary American foreign policy toward the Middle East and the Muslim world. Explores foreign policy decision making and international relations theory. Addresses major policy questions, including US reactions to the crisis in Syria and the Arab Spring.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MELC-M 281', 'QUR''ANIC ARABIC I', '29914', 'Class Status', 'Tu Tuesday 4:20 PM–6:50 PM', 'BH 333', 'Asaad Alsaleh', 6, NULL, 'Activity', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An intensive introduction to the language of the Qur''an - its vocabulary and grammar. Covers related materials such as Qur''anic commentary, history and Hadith. Teaches students to read classical and Qur''anic Arabic through a foundation in syntax and morphology.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 304', 'ISSUES IN MIDDLE EASTERN CULTURE AND SOCIETY', '29393', 'Class Status', 'Th Thursday 12:45 PM–3:15 PM', 'SY 137', 'Aziza Khazzoom', 14, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Explores particular problems, themes, and topics relating to the cultures of the Middle East in depth. Topics will vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MELC-M 304', 'ISSUES IN MIDDLE EASTERN CULTURE AND SOCIETY', '37318', 'Closed', 'TuTh Tuesday, Thursday 3:10 PM–5:40 PM', 'BH 336', 'John Walbridge', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Explores particular problems, themes, and topics relating to the cultures of the Middle East in depth. Topics will vary.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MELC-M 306', 'TOPICS IN MIDDLE EASTERN STUDIES', '12378', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'WB WEB', 'Attia Youseif', 5, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Covers selected topics in Middle Eastern Studies, from prehistory to the present day. Course content varies by instructor.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 306', 'TOPICS IN MIDDLE EASTERN STUDIES', '11716', 'Closed', 'Three Week', 'WB WEB', 'Asaad Alsaleh', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Covers selected topics in Middle Eastern Studies, from prehistory to the present day. Course content varies by instructor.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 306', 'TOPICS IN MIDDLE EASTERN STUDIES', '34566', 'Closed', 'Three Week', 'WB WEB', 'Asaad Alsaleh', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Covers selected topics in Middle Eastern Studies, from prehistory to the present day. Course content varies by instructor.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 334', 'WHAT IS MIDDLE EASTERN? PERSPECTIVES GAINED THROUGH COMPARISON WITH ISRAEL', '29394', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 313', 'Aziza Khazzoom', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines work that makes claims about Middle Eastern dynamics, by describing histories, gender regimes, secular/religious tensions, etc, that are perceived as common across Middle Eastern societies. Uses Israel, a possible Middle Eastern society, to provide a fresh perspective on what does and does not hold the Middle East together.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MELC-M 339', 'MIDDLE EASTERN POLITICS', '9367', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GA 1122', 'Ibrahim Gemeah', 12, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Explores political culture and change in selected Middle Eastern and North African countries. Topics covered include political elites, traditional cultures, modern political ideology, institutions of political control, conflict management, and social reform policies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MELC-M 347', 'RISE OF EASTERN ROME', '13729', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WH 106', 'Daniel Caner', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Covers the evolution of the Eastern Roman Empire in relation to Sassanian Persia from the second to seventh centuries, focusing on centralization at Constantinople; response to Western overlords; promotion of Christian orthodoxy, monasticism and Holy Land; and formulation of imperial strategies that defeated Persia but, ultimately, facilitated the Arab conquests.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('MELC-M 392', 'ISLAM AND MODERNITY', '29612', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0013', 'Asma Afsaruddin', 8, NULL, 'Discussion', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Islam and its compatibility with modernity is a much-debated issue in the contemporary period. This course addresses the important "hot-button" issues that are frequently raised in these debates: political Islam, democracy, pluralism, women''s rights, human rights, secularization and globalization, among others.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('MELC-M 444', 'ARABIC SOCIOLINGUISTICS', '29748', 'Class Status', NULL, NULL, 'Nader Morkus', 10, NULL, 'Discussion', '3', NULL, ARRAY[]::TEXT[], 'Explores the rich tapestry of Arabic sociolinguistics and investigates the dynamic interplay between language and society in the Arab World. Examines language contact, dialects, diglossia, code-switching, gender, identity, digital media, language attitudes and language policies.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 502', 'QUR''ANIC ARABIC I', '29915', 'Class Status', 'Tu Tuesday 4:20 PM–6:50 PM', 'BH 333', 'Asaad Alsaleh', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Dive into the basics of Qur''anic Arabic, focusing on foundational grammar, vocabulary, and sentence structure. Engage with short verses to develop reading and comprehension skills, setting the groundwork for deeper Quranic studies. Ideal for beginners eager to connect with the Qur''an''s original language.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 590', 'DIRECTED READINGS IN ARABIC', '2712', 'Class Status', NULL, NULL, 'Issam Albdairat', 8, NULL, 'Readings', '3', NULL, ARRAY[]::TEXT[], 'Reading and analysis of Arabic or translated texts selected in accordance with the student''s level and interests.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 598', 'INDIVIDUAL READINGS IN ARABIC LANGUAGE AND LINGUISTICS', '2714', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 7, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This reading course focuses on reading and analyzing materials in fields of Arabic language and linguistics. Students may register to research certain aspects of these fields that are not covered by the regular sequence of MELC courses.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 644', 'ARABIC SOCIOLINGUISTICS', '29749', 'Class Status', NULL, NULL, 'Nader Morkus', 10, NULL, 'Discussion', '3', NULL, ARRAY[]::TEXT[], 'In this course you will explore the rich tapestry of Arabic sociolinguistics and investigate the dynamic interplay between language and society in the Arab World. You will examine a variety of topics including language contact, dialects, diglossia, code-switching, gender, identity, digital media, language attitudes and language policies.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 682', 'ISLAM AND MODERNITY', '29613', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0013', 'Asma Afsaruddin', 8, NULL, 'Discussion', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Topics discussed in the context of Islam and modernity willl include political Islam, democracy, pluralism, gender, rights of religious minorities, secularization and globalization, among others.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 690', 'RESEARCH IN CLASSICAL ARABIC TEXTS', '29840', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SY 002', 'John Walbridge', 19, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'An introduction to the core questions of Islamic philosophical metaphysics. Readings will be arranged thematically and will sometimes include relevant Greek texts. All readings will be in English, with Arabic available.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 695', 'GRADUATE TOPICS IN MELC', '13730', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WH 106', 'Daniel Caner', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Special readings in Middle Eastern issues and problems within an interdisciplinary format. Variable topics. Previous topics include "Modern Middle East", "Texts and Authors", "Cultural History of Turkey", "Classical Arabic Rhetoric", and "Modern Persian Literature in Translation".', ARRAY[]::TEXT[], NULL),
    ('MELC-M 695', 'GRADUATE TOPICS IN MELC', '37319', 'Class Status', 'TuTh Tuesday, Thursday 3:10 PM–5:40 PM', 'BH 336', 'John Walbridge', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Special readings in Middle Eastern issues and problems within an interdisciplinary format. Variable topics. Previous topics include "Modern Middle East", "Texts and Authors", "Cultural History of Turkey", "Classical Arabic Rhetoric", and "Modern Persian Literature in Translation".', ARRAY[]::TEXT[], NULL),
    ('MELC-M 695', 'GRADUATE TOPICS IN MELC', '37375', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GA 1122', 'Ibrahim Gemeah', 12, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Special readings in Middle Eastern issues and problems within an interdisciplinary format. Variable topics. Previous topics include "Modern Middle East", "Texts and Authors", "Cultural History of Turkey", "Classical Arabic Rhetoric", and "Modern Persian Literature in Translation".', ARRAY[]::TEXT[], NULL),
    ('MELC-M 695', 'GRADUATE TOPICS IN MELC', '34567', 'Closed', 'Three Week', 'WB WEB', 'Asaad Alsaleh', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Special readings in Middle Eastern issues and problems within an interdisciplinary format. Variable topics. Previous topics include "Modern Middle East", "Texts and Authors", "Cultural History of Turkey", "Classical Arabic Rhetoric", and "Modern Persian Literature in Translation".', ARRAY[]::TEXT[], NULL),
    ('MELC-M 696', 'TEACHING LESS COMMONLY TAUGHT LANGUAGES', '9058', 'Class Status', 'W Wednesday 3:10 PM–5:40 PM', 'SY 006', 'Franziska Krueger', 8, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Develops and practices skills and techniques for teaching less commonly taught languages in the context of (a) recent approaches and research into language teaching, (b) national needs and standards, (c) fitting with the IU curriculum for these languages. The course concentrates on languages of the Mid East and Central Asia.', ARRAY[]::TEXT[], NULL),
    ('MELC-M 710', 'M A THESIS', '2715', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 8, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Master''s Thesis Hours', ARRAY[]::TEXT[], NULL),
    ('MELC-M 810', 'PHD THESIS', '2716', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 34, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Ph.D. Thesis Hours', ARRAY[]::TEXT[], NULL),
    ('MELC-M 810', 'PHD THESIS', '34770', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 13, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Ph.D. Thesis Hours', ARRAY[]::TEXT[], NULL),
    ('MELC-X 394', 'INDIVIDUALIZED READINGS IN MODERN ARABIC', '7656', 'Class Status', NULL, NULL, 'Nader Morkus, Asaad Alsaleh', 9, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Linguistic and literary analysis of selected modern Arabic texts.', ARRAY[]::TEXT[], NULL),
    ('MELC-X 399', 'READINGS FOR HONORS', '10731', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'The content of the course will vary by instructor, but in all cases students will be required to complete independent readings and/or research under the supervision of a faculty member in the Department. This course is intended to be used when a suitable course within the department is not available.', ARRAY[]::TEXT[], NULL),
    ('MELC-X 490', 'DIRECTED READINGS IN MIDDLE EASTERN LANGUAGES AND CULTURES', '8676', 'Class Status', NULL, NULL, 'Asaad Alsaleh', 1, NULL, 'Readings', '3–4', NULL, ARRAY[]::TEXT[], 'Study and analysis of selected issues and problems in Middle Eastern Languages and Cultures within an interdisciplinary format. Topics will vary and will ordinarily cut across fields, regions, or periods.', ARRAY[]::TEXT[], NULL),
    ('MEST-M 390', 'STUDIES IN MEDIEVAL CULTURE', '14628', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 242', 'Rega Wood', 1, NULL, 'Lecture', '3–4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examination and evaluation of various aspects, periods, and manifestations of medieval civilization. Student will be interdisciplinary, focusing on such subjects as Jews, Moslems, and Christians in the Middle Ages; the Carolingian Renaissance; multicultural Provence and its diaspora.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('MHO-M 201', 'ARTS OF COMMUNICATION', '9023', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 242', 'Anne Delgado', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces communication as a core practice in management and the workplace. Students work intensively to develop first simple, then increasingly complex, liberal arts communication competencies for business. These include formal presentations, one-on-one discussions, small-group work, and mediated communications.', ARRAY[]::TEXT[], NULL),
    ('MHO-M 301', 'EVIDENCE, ANALYSIS, AND WAYS OF KNOWING', '8346', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 342', 'Josh Hasler', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores how researchers from different disciplines and different methodological traditions frame research questions and use evidence to answer them. Reviews the strengths and weaknesses of each and shows that different kinds of questions lead to different methodological choices. Through an examination of a series of cases about social issues, economic life, and workplace dynamics, students learn that different disciplinary/ methodological perspectives can be brought to bear on the same issue.', ARRAY[]::TEXT[], NULL),
    ('MHO-M 401', 'CAPSTONE SEMINAR', '14506', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WH 203', 'Jacob Miller, Fabio Rojas', 0, NULL, 'Discussion', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Students address and analyze a complex, real-world problem related to management, business, and/or economic enterprise. Emphasis on identifying appropriate research strategies, finding relevant data/information, participating actively in collegial discussion and critique, working collaboratively, and communicating findings to diverse audiences.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MIL-G 101', 'LEADERSHIP AND PERSONAL DEVELOPMENT', '2190', 'Class Status', 'W Wednesday 10:25 AM–11:15 AM', 'WY 115', 'Ralph Vargas, Timothy Walton, Timothy Robinson, Joe Cross', 20, 'Lecture', 'Lecture', '2', 'WYLIE HALL', ARRAY[]::TEXT[], 'Students will learn how the personal development of life skills, such as goal setting, time management, physical fitness, and stress management relate to leadership, officership, and army profession.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 101', 'LEADERSHIP AND PERSONAL DEVELOPMENT', '2191', 'Class Status', 'Th Thursday 3:00 PM–7:00 PM', 'WH 100', 'Zachary McMillion, Dominique Bynum, Timothy Walton, Andrew Hasenfratz, Trevor Yust, Timothy Robinson, Ralph Vargas, Joe Cross', 5, 'Laboratory', 'Lecture', '2', 'WYLIE HALL', ARRAY[]::TEXT[], 'Students will learn how the personal development of life skills, such as goal setting, time management, physical fitness, and stress management relate to leadership, officership, and army profession.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 101', 'LEADERSHIP AND PERSONAL DEVELOPMENT', '2189', 'Closed', 'Tu Tuesday 3:25 PM–4:15 PM', 'BH 147', 'Ralph Vargas, Timothy Walton, Joe Cross, Timothy Robinson', 0, 'Lecture', 'Lecture', '2', 'WYLIE HALL', ARRAY[]::TEXT[], 'Students will learn how the personal development of life skills, such as goal setting, time management, physical fitness, and stress management relate to leadership, officership, and army profession.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 201', 'INNOVATIVE TACTICAL LEADERSHIP', '2192', 'Class Status', 'M Monday 1:55 PM–3:50 PM', 'SY 108', 'Ralph Vargas, Timothy Walton, Trevor Yust, Dominique Bynum', 1, 'Lecture', 'Lecture', '2', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Students will explore the dimensions of creative and innovative tactical leadership strategies and styles by studying historical case studies and engaging in interactive student exercise. Cadets practice aspects of personal motivation and team building in the context of planning, executing and assessing team exercise. Leadership labs, physical training sessions, and weekend field training exercise are optional, but available to those looking for more out of their college experience.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 201', 'INNOVATIVE TACTICAL LEADERSHIP', '2194', 'Class Status', 'Th Thursday 3:00 PM–7:00 PM', 'WH 100', 'Zachary McMillion, Dominique Bynum, Timothy Walton, Andrew Hasenfratz, Trevor Yust, Timothy Robinson, Ralph Vargas, Joe Cross', 3, 'Laboratory', 'Lecture', '2', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Students will explore the dimensions of creative and innovative tactical leadership strategies and styles by studying historical case studies and engaging in interactive student exercise. Cadets practice aspects of personal motivation and team building in the context of planning, executing and assessing team exercise. Leadership labs, physical training sessions, and weekend field training exercise are optional, but available to those looking for more out of their college experience.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 201', 'INNOVATIVE TACTICAL LEADERSHIP', '2193', 'Class Status', 'Tu Tuesday 1:55 PM–3:50 PM', 'AC C101', 'Ralph Vargas, Timothy Walton, Trevor Yust, Dominique Bynum', 2, 'Lecture', 'Lecture', '2', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Students will explore the dimensions of creative and innovative tactical leadership strategies and styles by studying historical case studies and engaging in interactive student exercise. Cadets practice aspects of personal motivation and team building in the context of planning, executing and assessing team exercise. Leadership labs, physical training sessions, and weekend field training exercise are optional, but available to those looking for more out of their college experience.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 290', 'INDEPENDENT STUDY', '2195', 'Class Status', NULL, NULL, 'Timothy Walton', 19, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('MIL-G 301', 'ADAPTIVE TEAM LEADERSHIP', '2196', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 229', 'Timothy Walton, Andrew Hasenfratz, Ralph Vargas, Zachary McMillion', 8, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course prepares cadets for success at the Leadership Development and Assessments course and as Army officers. Opportunities to lead small teams and receive personal assessments make up the leadership development program. Instruction in troop leading procedures and operations orders is emphasized.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 301', 'ADAPTIVE TEAM LEADERSHIP', '2197', 'Class Status', 'Th Thursday 3:00 PM–7:00 PM', 'WH 100', 'Zachary McMillion, Dominique Bynum, Timothy Walton, Andrew Hasenfratz, Trevor Yust, Timothy Robinson, Ralph Vargas, Joe Cross', 8, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course prepares cadets for success at the Leadership Development and Assessments course and as Army officers. Opportunities to lead small teams and receive personal assessments make up the leadership development program. Instruction in troop leading procedures and operations orders is emphasized.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 301', 'ADAPTIVE TEAM LEADERSHIP', '3651', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:15 PM', 'SY 212', 'Timothy Walton, Andrew Hasenfratz, Ralph Vargas, Zachary McMillion', 0, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course prepares cadets for success at the Leadership Development and Assessments course and as Army officers. Opportunities to lead small teams and receive personal assessments make up the leadership development program. Instruction in troop leading procedures and operations orders is emphasized.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 401', 'DEVELOPING ADAPTIVE LEADERS', '2198', 'Class Status', 'Tu Tuesday 8:00 AM–10:15 AM', 'WY 115 GY 1045', 'Andrew Hasenfratz, Ralph Vargas, Timothy Walton', 6, 'Lecture', 'Lecture', '3', 'WYLIE HALL, GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Develop proficiency in planning, executing, and assessing complex operations; functioning as a staff member; and providing leadership performance feedback to subordinates. Cadets are given situational opportunities to assess risk, make ethical decisions and provide coaching to fellow ROTC cadets. Leadership labs, physical training, and a week field training exercise are mandatory requirements.', ARRAY[]::TEXT[], NULL),
    ('MIL-G 401', 'DEVELOPING ADAPTIVE LEADERS', '2199', 'Class Status', 'Th Thursday 3:00 PM–7:00 PM', 'WH 100', 'Zachary McMillion, Dominique Bynum, Timothy Walton, Andrew Hasenfratz, Trevor Yust, Timothy Robinson, Ralph Vargas, Joe Cross', 1, 'Laboratory', 'Lecture', '3', 'WYLIE HALL, GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Develop proficiency in planning, executing, and assessing complex operations; functioning as a staff member; and providing leadership performance feedback to subordinates. Cadets are given situational opportunities to assess risk, make ethical decisions and provide coaching to fellow ROTC cadets. Leadership labs, physical training, and a week field training exercise are mandatory requirements.', ARRAY[]::TEXT[], NULL),
    ('MLS-M 410', 'PROTEIN METABOLISM', '8535', 'Class Status', 'MW Monday, Wednesday 3:15 PM–4:30 PM', 'SI 001', 'Lingling Chen', 11, NULL, 'Lecture', '3', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Focuses on the mechanisms and enzymes that synthesize, fold, traffic and degrade proteins. Provides a molecular and structural view of key processes such as translation, folding, membrane insertion, vesicular trafficking, post-translational modification and protein degradation. Emphasizes broader principles such as NTP switches as regulators and macromolecular interaction events; explains how cellular architecture underpins function. Describes structural and mechanistic features of protein metabolism in a cellular context.', ARRAY[]::TEXT[], NULL),
    ('MLS-M 420', 'GENOME DUPLICATION AND MAINTENANCE', '8534', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SI 001', 'Matt Bochman', 17, NULL, 'Lecture', '3', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Examines genomic structure, DNA topology and replication mechanisms in the context of cell function for all three domains of life. Studies the pathological consequences of failure to duplicate and maintain the genome.', ARRAY[]::TEXT[], NULL),
    ('MSCH-A 250', 'FOUNDATIONS OF ADVERTISING', '35145', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'TV 251', 'Joe Glennon', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introduces the fundamentals of media advertising theory, planning and practice. Explores the techniques, skills and tools necessary for effective brand management and creative development.', ARRAY[]::TEXT[], NULL),
