    ('MSCH-B 330', 'SPORTS MEDIA LITERACY', '12180', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TV 251', 'Brandon Wallace', 2, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introduces key concepts, historical elements, and future considerations within the areas of sports and media, emphasizing how these two fields interact. Geared toward preparation for careers in sports journalism and sports media.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-B 331', 'MANAGING SPORTS MEDIA', '14056', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'TV 180', 'Nicky Lewis', 0, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Overview of the sports media industry including processes of content distribution, finance, and technology. Provides historical background of the business of media. Students learn about the symbiotic financial relationship between sports and the media, including team- and league-based media that compete with traditional media.', ARRAY[]::TEXT[], NULL),
    ('MSCH-B 332', 'SPORTS WRITING AND REPORTING', '7297', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'FF 058', 'Michael Wells', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops the research, writing, and reporting skills necessary to effectively cover teams, leagues, athletes, and other parts of the sports industry. Provides opportunities to gain hands-on experience writing and researching sports stories.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('MSCH-B 332', 'SPORTS WRITING AND REPORTING', '30293', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'FF 058', 'Craig Fehrman', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Develops the research, writing, and reporting skills necessary to effectively cover teams, leagues, athletes, and other parts of the sports industry. Provides opportunities to gain hands-on experience writing and researching sports stories.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
