    ('MSCH-C 110', 'MISINFORMATION AND MEDIA LITERACY', '32889', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 310', 'Taeyoung Lee', 2, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Explores disinformation, fake news, social bots, echo chambers, astroturf, troll factories, conspiracy theories, and coordinated inauthentic influence campaigns that people experience every day. Helps students gain knowledge and skills in building media and information literacy as well as algorithmic countermeasures against social media abuse and manipulation.', ARRAY[]::TEXT[], NULL),
