    ('MSCH-C 150', 'MEDIA SCHOOL COLLEGE AND CAREER PREPARATION', '35587', 'Closed', 'Tu Tuesday 3:55 PM–4:45 PM', 'BH 245', 'Ruth Witmer', 0, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides information on how to succeed in the Media School and prepare for careers in the media industry. Explores ways to connect academic experiences with internship and job opportunities. Highlights the array of media careers and presents insights on industry expectations for interviewing, portfolios, and resumes.', ARRAY['COLL (CASE) Career Readiness 1'], NULL),
    ('MSCH-C 150', 'MEDIA SCHOOL COLLEGE AND CAREER PREPARATION', '35588', 'Closed', 'Th Thursday 5:30 PM–6:20 PM', 'BH 139', 'Kari Krafft', 0, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides information on how to succeed in the Media School and prepare for careers in the media industry. Explores ways to connect academic experiences with internship and job opportunities. Highlights the array of media careers and presents insights on industry expectations for interviewing, portfolios, and resumes.', ARRAY['COLL (CASE) Career Readiness 1'], NULL),
    ('MSCH-C 150', 'MEDIA SCHOOL COLLEGE AND CAREER PREPARATION', '36359', 'Closed', 'M Monday 5:30 PM–6:20 PM', 'LI 044B', 'Mary Ducette', 0, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Provides information on how to succeed in the Media School and prepare for careers in the media industry. Explores ways to connect academic experiences with internship and job opportunities. Highlights the array of media careers and presents insights on industry expectations for interviewing, portfolios, and resumes.', ARRAY['COLL (CASE) Career Readiness 1'], NULL),
    ('MSCH-C 160', 'THE MEDIA VILLAGE', '4363', 'Class Status', 'Tu Tuesday 5:30 PM–6:45 PM', 'FF 312', 'Hannah Holtz', 8, NULL, 'Lecture', '1', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Brings together students in the LLC with shared academic and professional interests for events, speakers, reading and discussions about media and journalism in the twenty-first century. Will establish a unique model of individual learning, College of One, based on the value of experiences beyond the classroom.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 200', 'THE VIDEOGAME INDUSTRY: SYSTEMS AND MANAGEMENT', '6677', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 312', 'Adam Stichter', 27, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examines the marketplaces for games and for game-related jobs. Students learn about the game production process, strategies for turning profits, and tips for finding good jobs in this rapidly growing industry.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-C 203', 'FOUNDATIONS OF JOURNALISM', '10372', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 015', 'Teresa White', 13, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'A robust introduction to the field of journalism and the underlying principles of journalism. Explores the role of journalists and media in American society, the influences of news and entertainment media on audiences, and the role of journalism in modern media environments.', ARRAY['IUB GenEd S&H credit
Class uses IU eTexts'], NULL),
    ('MSCH-C 207', 'INTRODUCTION TO MEDIA INDUSTRY AND MANAGEMENT', '5573', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'TV 251', 'Matt Pierce', 40, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Introductory analysis using case-study method of how media industries such as broadcasting, cable, and telephony are structured, funded, and regulated; how media organizations create and market programs and products, and how they manage their operations.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-C 208', 'PRINCIPLES OF PUBLIC RELATIONS', '11824', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'MY 130', 'Nicholas Browning', 15, NULL, 'Lecture', '3', 'MYERS HALL', ARRAY[]::TEXT[], 'Introduction to public relations. Examines theory and practice of public relations, how public relations operates in organizations, and its impact on stakeholders and society. Topics include approaches to persuasion, media relations, crisis communication, reputation management, and ethics.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 209', 'INTRODUCTION TO ADVERTISING AND INTEGRATED MARKETING COMMUNICATION', '8566', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'OP 105', 'Ted Jamison-Koenig', 1, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Examines principles of media advertising and applications across platforms and audiences. Analyzes the advertising industry structures and processes, including the roles of agencies, creative teams, station representatives, and buyers. Topics include the social and individual effects of advertising, ethical issues in advertising, and considerations for advertising in a global marketplace.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-C 209', 'INTRODUCTION TO ADVERTISING AND INTEGRATED MARKETING COMMUNICATION', '8567', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'TV 251', 'Ted Jamison-Koenig', 39, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Examines principles of media advertising and applications across platforms and audiences. Analyzes the advertising industry structures and processes, including the roles of agencies, creative teams, station representatives, and buyers. Topics include the social and individual effects of advertising, ethical issues in advertising, and considerations for advertising in a global marketplace.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-C 209', 'INTRODUCTION TO ADVERTISING AND INTEGRATED MARKETING COMMUNICATION', '10236', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'TV 251', 'Joe Glennon', 15, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Examines principles of media advertising and applications across platforms and audiences. Analyzes the advertising industry structures and processes, including the roles of agencies, creative teams, station representatives, and buyers. Topics include the social and individual effects of advertising, ethical issues in advertising, and considerations for advertising in a global marketplace.', ARRAY['Class uses IU eTexts'], NULL),
    ('MSCH-C 210', 'INTRODUCTION TO GAMES', '6058', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SB 015', 'William Emigh', 27, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Introduces the idea of games systems by breaking down games into their different components to build a deep game literacy. Students will learn how to learn a new game quickly; teach complex games to others; recognize and excel at the many different games played in everyday life. Where most courses have readings, this course has "gamings," required games for students to play and learn.', ARRAY[]::TEXT[], NULL),
    ('MSCH-C 211', 'SCREENING GENDER AND SEXUALITY', '8876', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'FF 003', 'Megan Connor', 0, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Critically examines how gender and sexuality are mediated through screen and audio-visual media (including film, video, television, radio, internet) and their cultural contexts. Using humanities approaches, topics might focus on popular media production; various genres, movements, and media cycles; specific cultural and historical contexts; impacts of technological change. Screenings may be required.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-C 213', 'INTRODUCTION TO MEDIA PSYCHOLOGY', '6518', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 110', 'John Velez', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the construction of social meaning associated with mediated messages as well as the range of uses of and consequences of exposure to mediated messages in individual groups, organizations, and society.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-C 213', 'INTRODUCTION TO MEDIA PSYCHOLOGY', '8988', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TV 251', 'John Velez', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the construction of social meaning associated with mediated messages as well as the range of uses of and consequences of exposure to mediated messages in individual groups, organizations, and society.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('MSCH-C 218', 'SPORTS, MEDIA AND SOCIETY', '12332', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'TV 251', 'Brandon Wallace', 3, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Examination of the social and financial relationships between sports organizations, media and society. Study of the social implications of sports media content in light of economic connections between sports media and college and professional sports teams, including how television contracts influence media coverage and how organization-based media influence audience perceptions.', ARRAY['Class uses IU eTexts'], NULL)
